const emails = $input.first().json.Attendees_Gmails
  .split(',').map(e => e.trim()).filter(e => e.length > 0);

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const invalidEmails = emails.filter(e => !emailRegex.test(e));
const validEmails = emails.filter(e => emailRegex.test(e));

return [{
  json: {
    totalEmailsCount: emails.length,
    validEmailsCount: validEmails.length,
    emails: validEmails,
    invalidEmails: invalidEmails
  }
}];

const input = $input.first().json;

// Try all possible field names
const duration = input['Duration'] || input['duration'] || 
                 $('On form submission').item.json['Duration'] || '';

let minutes = 0;

if (duration.includes('30')) minutes = 30;
else if (duration.includes('1.5')) minutes = 90;
else if (duration.includes('2')) minutes = 120;
else if (duration.includes('1')) minutes = 60;

return [{ json: { ...input, durationInMinutes: minutes } }];

const newStart = new Date($('Edit Fields').item.json['Date/Time']).getTime();
const newDuration = $('Edit Fields').item.json.durationInMinutes;
const newEnd = newStart + (newDuration * 60 * 1000);

const meetings = $input.all();

// Agar koi meetings nahi hain toh conflict nahi
if (meetings.length === 0) {
  return [{ json: { conflict: false, conflictDetails: {} } }];
}

let conflict = false;
let conflictDetails = {};

for (const meeting of meetings) {
  const m = meeting.json;
  if (m.Status === 'Cancelled') continue;

  const exStart = new Date(m['Date/Time']).getTime();
  const exEnd = exStart + (m['Duration(mins)'] * 60 * 1000);
  const buffer = 60 * 60 * 1000;

  if (newStart < exEnd + buffer && newEnd > exStart - buffer) {
    conflict = true;
    conflictDetails = {
      title: m.Title,
      dateTime: m['Date/Time'],
      duration: m['Duration(mins)']
    };
    break;
  }
}

return [{ json: { conflict, conflictDetails } }];

const now = new Date().getTime();
const results = [];

for (const item of $input.all()) {
  const m = item.json;
  const endTime = new Date(m['Date/Time']).getTime() + (m['Duration(mins)'] * 60 * 1000);
  if (endTime < now) {
    results.push({ json: m });
  }
}

return results;

const { DateTime } = require('luxon');

const now = DateTime.now().setZone('Asia/Karachi');
const weekStart = now.startOf('week');
const weekEnd = now.endOf('week');

const meetings = $input.all().filter(item => {
  const dt = DateTime.fromISO(item.json['Date/Time'], { zone: 'Asia/Karachi' });
  return dt >= weekStart && dt <= weekEnd;
});

if (meetings.length === 0) {
  return [{ json: { html: '<p>No meetings scheduled this week.</p>' } }];
}

let rows = meetings.map(item => {
  const m = item.json;
  return `<tr>
    <td>${m.Title}</td>
    <td>${m['Date/Time']}</td>
    <td>${m.Attendees}</td>
    <td>${m.Status}</td>
    <td>${m.Gist}</td>
  </tr>`;
}).join('');

const html = `
<h2>Weekly Meeting Digest</h2>
<table border="1" cellpadding="8" cellspacing="0">
  <tr>
    <th>Title</th>
    <th>Date/Time</th>
    <th>Attendees</th>
    <th>Status</th>
    <th>Gist</th>
  </tr>
  ${rows}
</table>`;

return [{ json: { html } }];

const now = new Date().getTime();
const thirtyDays = 30 * 24 * 60 * 60 * 1000;
const results = [];

for (const item of $input.all()) {
  const m = item.json;
  if (m.Status === 'Done') {
    const meetingTime = new Date(m['Date/Time']).getTime();
    if (now - meetingTime > thirtyDays) {
      results.push({
        json: {
          ...m,
          ArchivedOn: new Date().toISOString()
        }
      });
    }
  }
}

return results;

const items = $input.all();
items.sort((a, b) => b.json.row_number - a.json.row_number);
return items;
